const https = require('https');
const { execFileSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

const data = $('Webhook').first().json.body;

// --- Step 1: Download template via pre-authenticated URL ---
const downloadUrl = $('Get Download URL').first().json['@microsoft.graph.downloadUrl'];
console.log('Download URL obtained, fetching template...');

const templateBuffer = await new Promise((resolve, reject) => {
  https.get(downloadUrl, (res) => {
    if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
      https.get(res.headers.location, (redirectRes) => {
        const chunks = [];
        redirectRes.on('data', chunk => chunks.push(chunk));
        redirectRes.on('end', () => resolve(Buffer.concat(chunks)));
        redirectRes.on('error', reject);
      }).on('error', reject);
      return;
    }
    const chunks = [];
    res.on('data', chunk => chunks.push(chunk));
    res.on('end', () => resolve(Buffer.concat(chunks)));
    res.on('error', reject);
  }).on('error', reject);
});
console.log('Template buffer: ' + templateBuffer.length + ' bytes');

if (templateBuffer.length < 1000) {
  throw new Error('Template too small (' + templateBuffer.length + ' bytes). Expected ~15kB docx file.');
}

// --- Step 2: Map webhook camelCase fields to UPPER_SNAKE template tags ---
const templateData = {
  FIRM_NAME: data.firmName || '',
  CLIENT_NAME: data.clientName || '',
  REPORT_PERIOD: data.reportPeriod || '',
  REPORT_DATE: data.reportDate || '',
  ADVISOR_NAME: data.advisorName || '',
  MEETING_DATE: data.meetingDate || '',
  MEETING_LOCATION: data.meetingLocation || '',
  ATTENDEES: data.attendees || '',
  MEETING_DURATION: data.meetingDuration || '',
  DISCUSSION_POINT_1: data.discussionPoint1 || '',
  DISCUSSION_POINT_2: data.discussionPoint2 || '',
  DISCUSSION_POINT_3: data.discussionPoint3 || '',
  ADVISOR_NOTES: data.advisorNotes || '',
  PORTFOLIO_VALUE: data.portfolioValue || '',
  YTD_RETURN: data.ytdReturn || '',
  BENCHMARK_RETURN: data.benchmarkReturn || '',
  VS_BENCHMARK: data.vsBenchmark || '',
  GOAL_1: data.goal1 || '',
  GOAL_2: data.goal2 || '',
  GOAL_3: data.goal3 || '',
  GOALS_PROGRESS_NOTES: data.goalsProgressNotes || '',
  ACTION_1: data.action1 || '',
  ACTION_1_OWNER: data.action1Owner || '',
  ACTION_1_DUE: data.action1Due || '',
  ACTION_2: data.action2 || '',
  ACTION_2_OWNER: data.action2Owner || '',
  ACTION_2_DUE: data.action2Due || '',
  ACTION_3: data.action3 || '',
  ACTION_3_OWNER: data.action3Owner || '',
  ACTION_3_DUE: data.action3Due || '',
  NEXT_MEETING_DATE: data.nextMeetingDate || '',
  NEXT_MEETING_AGENDA: data.nextMeetingAgenda || '',
  ACCOUNT_NUMBER: data.accountNumber || '',
  ACCOUNT_TYPE: data.accountType || '',
  RISK_PROFILE: data.riskProfile || '',
};

// --- Step 3: Write temp files and run docxtemplater via execFileSync ---
const ts = Date.now();
const tmpDir = os.tmpdir();
const tplPath = path.join(tmpDir, 'docgen-tpl-' + ts + '.docx');
const dataPath = path.join(tmpDir, 'docgen-data-' + ts + '.json');
const scriptPath = path.join(tmpDir, 'docgen-script-' + ts + '.js');

fs.writeFileSync(tplPath, templateBuffer);
fs.writeFileSync(dataPath, JSON.stringify(templateData));

const script = `
const PizZip = require('pizzip');
const Docxtemplater = require('docxtemplater');
const InspectModule = require('docxtemplater/js/inspect-module.js');
const fs = require('fs');

const tplBuf = fs.readFileSync(process.argv[2]);
const data = JSON.parse(fs.readFileSync(process.argv[3], 'utf8'));

// First pass: inspect all tags in the template
const inspectZip = new PizZip(tplBuf);
const iModule = new InspectModule();
try {
  const inspectDoc = new Docxtemplater(inspectZip, {
    modules: [iModule],
    delimiters: { start: '{{', end: '}}' },
  });
} catch (e) {}
const allTags = iModule.getAllTags();
const tagNames = Object.keys(allTags);
console.error('TEMPLATE TAGS FOUND (' + tagNames.length + '): ' + tagNames.join(', '));

// Log which tags have data vs which are missing
const provided = Object.keys(data);
const missing = tagNames.filter(t => !provided.includes(t));
const extra = provided.filter(t => !tagNames.includes(t));
if (missing.length) console.error('TAGS IN TEMPLATE BUT NOT IN DATA: ' + missing.join(', '));
if (extra.length) console.error('TAGS IN DATA BUT NOT IN TEMPLATE: ' + extra.join(', '));

// Second pass: render with nullGetter to replace missing tags with empty string
const zip = new PizZip(tplBuf);
const doc = new Docxtemplater(zip, {
  delimiters: { start: '{{', end: '}}' },
  paragraphLoop: true,
  linebreaks: true,
  nullGetter(part) {
    if (!part.module) {
      console.error('UNRESOLVED TAG during render: ' + part.value);
    }
    return '';
  },
});

doc.render(data);

const buf = doc.getZip().generate({ type: 'nodebuffer', compression: 'DEFLATE' });
process.stdout.write(buf.toString('base64'));
`;
fs.writeFileSync(scriptPath, script);

let outputBase64;
try {
  outputBase64 = execFileSync('node', [scriptPath, tplPath, dataPath], {
    maxBuffer: 50 * 1024 * 1024,
    encoding: 'utf8',
    stdio: ['pipe', 'pipe', 'pipe'],
  });
} catch (execErr) {
  // Log stderr from the helper script even on failure
  if (execErr.stderr) console.log('Helper stderr:\n' + execErr.stderr.toString());
  throw new Error('docxtemplater failed: ' + (execErr.stderr ? execErr.stderr.toString() : execErr.message));
} finally {
  // Cleanup temp files
  try { fs.unlinkSync(tplPath); } catch (_) {}
  try { fs.unlinkSync(dataPath); } catch (_) {}
  try { fs.unlinkSync(scriptPath); } catch (_) {}
}

console.log('Output base64 length: ' + outputBase64.length);

const fileName = (data.clientName || 'Report') + '-' + (data.reportPeriod || 'Report') + '.docx';

return [{
  binary: {
    data: {
      data: outputBase64,
      mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      fileName: fileName,
      fileExtension: 'docx'
    }
  },
  json: { fileName: fileName }
}];
